external_knowledge:
- 'size 2': a specific size designation in clothing items;
- 'abound in the warehouse': the quantity in stock is greater than zero;
- 'ocean of men's fashion': a metaphor for a large collection of men's clothing items;
- 'visual portraits': refers to the image URLs of the clothing items.

sql:
SELECT COUNT(*) 
FROM inventory i 
WHERE i.quantity < i.restock_level;

SELECT DISTINCT item_name 
FROM clothing_items 
WHERE category = 'women';

SELECT item_name, price, category
FROM clothing_items
WHERE price > (SELECT AVG(price) FROM clothing_items);

SELECT GROUP_CONCAT(item_name, ', ') AS 'Items priced above average'
FROM clothing_items
WHERE price > (SELECT AVG(price) FROM clothing_items);

SELECT item_name, description, price, category, sub_category, brand, color, material
FROM clothing_items
WHERE category IN ('men', 'women');

SELECT size_id
FROM sizes
WHERE size_id NOT IN (
  SELECT size_id 
  FROM inventory
);

SELECT item_name, description
FROM clothing_items
WHERE item_id = 1;

SELECT ci.sub_category, AVG(ci.price) AS average_price
FROM clothing_items ci
GROUP BY ci.sub_category;
